import os
import numpy as np
from transformers import AutoTokenizer, AutoModelForSequenceClassification, AutoConfig
from sklearn.feature_extraction.text import TfidfVectorizer

# Load company documents into vector database
with open('company_documents.txt', 'r') as f:
    docs = [doc.strip() for doc in f]

# Initialize tokenizer and model for sequence classification
tokenizer = AutoTokenizer.from_pretrained('bert-base-uncased')
model = AutoModelForSequenceClassification.from_pretrained('bert-base-uncased', num_labels=2)

# Define function to convert text to vector and predict labels
def predict_labels(text):
    inputs = tokenizer.encode_plus(text, 
                                  add_special_tokens=True, 
                                  max_length=512, 
                                  padding='max_length', 
                                  truncation=True)
    
    input_ids = inputs['input_ids']
    attention_mask = inputs['attention_mask']
    
    with torch.no_grad():
        outputs = model(input_ids, attention_mask)
    
    logits = outputs[0]
    label_id = torch.argmax(logits).item()
    return label_id

# Define function to retrieve relevant documents
def retrieve_documents(query):
    vectorizer = TfidfVectorizer()
    query_vector = vectorizer.fit_transform([query])
    
    distances = []
    for doc in docs:
        doc_vector = vectorizer.transform([doc])
        cosine_similarity = query_vector.dot(doc_vector.T) / (np.linalg.norm(query_vector) * np.linalg.norm(doc_vector))
        distances.append((cosine_similarity, doc))
    
    sorted_distances = sorted(distances, key=lambda x: x[0], reverse=True)
    relevant_documents = [doc for cosine_similarity, doc in sorted_distances if cosine_similarity > 0.5]
    return relevant_documents

# Define function to generate prompt
def generate_prompt(relevant_documents):
    LLM_prompt = ''
    for doc in relevant_documents:
        LLM_prompt += f'[CLS] {doc} [SEP]'
    return LLM_prompt

# Define function to accept user queries and retrieve relevant context
def handle_user_query(query):
    label = predict_labels(query)
    if label == 1: # positive label
        relevant_documents = retrieve_documents(query)
        LLM_prompt = generate_prompt(relevant_documents)
        return LLM_prompt
    else: # negative label
        return 'I don\'t have any information about that.'